"""A readable parser for standard 5-field cron expressions.

A cron expression has the form:

    "minute hour day_of_month month day_of_week"

Each field supports wildcards (*), ranges (1-5), lists (1,3,5),
steps (*/15 or 1-30/5), and single values (42).

The public entry point is :func:`parse`, which returns a
:class:`CronSchedule`. Call :meth:`CronSchedule.describe` for a
human-readable English summary.
"""

from __future__ import annotations

from dataclasses import dataclass


# --------------------------------------------------------------------------- #
# Field definitions
# --------------------------------------------------------------------------- #

@dataclass(frozen=True)
class FieldRange:
    """The legal bounds and display name of a single cron field."""

    name: str
    minimum: int
    maximum: int


# The five fields, in the order they appear in a cron expression.
FIELD_RANGES: tuple[FieldRange, ...] = (
    FieldRange("minute", 0, 59),
    FieldRange("hour", 0, 23),
    FieldRange("day_of_month", 1, 31),
    FieldRange("month", 1, 12),
    FieldRange("day_of_week", 0, 6),
)

MONTH_NAMES: tuple[str, ...] = (
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December",
)

# Cron weekdays: 0 = Sunday ... 6 = Saturday.
DAY_NAMES: tuple[str, ...] = (
    "Sunday", "Monday", "Tuesday", "Wednesday",
    "Thursday", "Friday", "Saturday",
)


class CronParseError(ValueError):
    """Raised when a cron expression cannot be parsed."""


# --------------------------------------------------------------------------- #
# Parsed representation
# --------------------------------------------------------------------------- #

@dataclass(frozen=True)
class Field:
    """A single parsed cron field.

    ``values`` is the fully-expanded, sorted set of matching numbers.
    ``raw`` and ``step`` are kept so descriptions can reflect the
    original intent (e.g. "every 15 minutes" rather than a value list).
    """

    raw: str
    values: tuple[int, ...]
    step: int | None

    @property
    def is_wildcard(self) -> bool:
        return self.raw == "*"

    @property
    def is_single_value(self) -> bool:
        return len(self.values) == 1

    @property
    def is_simple_range(self) -> bool:
        """True for an unstepped range like ``1-5``."""
        return "-" in self.raw and "/" not in self.raw and "," not in self.raw


@dataclass(frozen=True)
class CronSchedule:
    """A fully parsed cron expression."""

    minute: Field
    hour: Field
    day_of_month: Field
    month: Field
    day_of_week: Field

    def describe(self) -> str:
        """Return a human-readable English description of the schedule."""
        clauses: list[str] = [_describe_time(self.minute, self.hour)]

        day_clause = _describe_day_of_month(self.day_of_month, self.month)
        if day_clause is not None:
            clauses.append(day_clause)
        elif not self.month.is_wildcard:
            clauses.append(_describe_month(self.month))

        weekday_clause = _describe_day_of_week(self.day_of_week)
        if weekday_clause is not None:
            clauses.append(weekday_clause)

        return " ".join(clauses)


# --------------------------------------------------------------------------- #
# Parsing
# --------------------------------------------------------------------------- #

def parse(expression: str) -> CronSchedule:
    """Parse a 5-field cron expression into a :class:`CronSchedule`."""
    tokens = _split_into_fields(expression)
    fields = tuple(
        _parse_field(token, field_range)
        for token, field_range in zip(tokens, FIELD_RANGES)
    )
    return CronSchedule(*fields)


def _split_into_fields(expression: str) -> list[str]:
    """Split an expression into exactly five whitespace-separated tokens."""
    tokens = expression.split()
    if len(tokens) != len(FIELD_RANGES):
        raise CronParseError(
            f"Expected {len(FIELD_RANGES)} fields, got {len(tokens)}: "
            f"{expression!r}"
        )
    return tokens


def _parse_field(token: str, field_range: FieldRange) -> Field:
    """Parse one field token (the shared logic for all five fields).

    Handles wildcards, ranges, lists, steps, and single values by
    delegating each comma-separated component to :func:`_parse_component`.
    """
    values: set[int] = set()
    step: int | None = None

    for component in token.split(","):
        component_values, component_step = _parse_component(component, field_range)
        values.update(component_values)
        step = step or component_step

    if not values:
        raise CronParseError(f"Empty {field_range.name} field: {token!r}")

    return Field(raw=token, values=tuple(sorted(values)), step=step)


def _parse_component(
    component: str, field_range: FieldRange
) -> tuple[set[int], int | None]:
    """Parse one comma-separated component, e.g. ``*``, ``1-5``, or ``*/15``.

    Returns the matching values and the step size (if a ``/step`` was given).
    """
    base, step = _split_step(component, field_range)
    low, high = _parse_base_range(base, field_range)
    return set(range(low, high + 1, step)), (step if step != 1 else None)


def _split_step(component: str, field_range: FieldRange) -> tuple[str, int]:
    """Separate a ``base/step`` component into its base and step parts."""
    if "/" not in component:
        return component, 1

    base, _, step_text = component.partition("/")
    step = _parse_int(step_text, field_range)
    if step < 1:
        raise CronParseError(
            f"Step must be positive in {field_range.name}: {component!r}"
        )
    return base, step


def _parse_base_range(base: str, field_range: FieldRange) -> tuple[int, int]:
    """Resolve the base of a component into an inclusive ``(low, high)`` range."""
    if base == "*":
        return field_range.minimum, field_range.maximum

    if "-" in base:
        low_text, _, high_text = base.partition("-")
        low = _parse_int(low_text, field_range)
        high = _parse_int(high_text, field_range)
        if low > high:
            raise CronParseError(
                f"Range start exceeds end in {field_range.name}: {base!r}"
            )
        return low, high

    value = _parse_int(base, field_range)
    return value, value


def _parse_int(text: str, field_range: FieldRange) -> int:
    """Parse and bounds-check a single integer for a given field."""
    try:
        value = int(text)
    except ValueError:
        raise CronParseError(
            f"Invalid {field_range.name} value: {text!r}"
        ) from None

    if not field_range.minimum <= value <= field_range.maximum:
        raise CronParseError(
            f"{field_range.name} value {value} out of range "
            f"[{field_range.minimum}, {field_range.maximum}]"
        )
    return value


# --------------------------------------------------------------------------- #
# Description helpers
# --------------------------------------------------------------------------- #

def _describe_time(minute: Field, hour: Field) -> str:
    """Describe the time-of-day portion (the leading clause)."""
    if minute.is_wildcard and hour.is_wildcard:
        return "Every minute"

    if minute.raw.startswith("*/") and hour.is_wildcard:
        return f"Every {minute.step} minutes"

    if hour.raw.startswith("*/") and minute.values == (0,):
        return f"Every {hour.step} hours, on the hour"

    if minute.is_single_value and hour.is_single_value:
        return _describe_clock_time(hour.values[0], minute.values[0])

    return (
        f"At minute {_join_numbers(minute.values)} "
        f"past hour {_join_numbers(hour.values)}"
    )


def _describe_clock_time(hour: int, minute: int) -> str:
    """Render a single wall-clock time, e.g. ``At 08:30`` or ``At midnight``."""
    if hour == 0 and minute == 0:
        return "At midnight"
    return f"At {hour:02d}:{minute:02d}"


def _describe_day_of_month(day_of_month: Field, month: Field) -> str | None:
    """Describe the day-of-month clause, folding in the month if present."""
    if day_of_month.is_wildcard:
        return None

    days = _join_text(_ordinal(day) for day in day_of_month.values)
    where = "every month" if month.is_wildcard else _join_month_names(month)
    return f"on the {days} of {where}"


def _describe_month(month: Field) -> str:
    """Describe a standalone month clause, e.g. ``in January``."""
    return f"in {_join_month_names(month)}"


def _describe_day_of_week(day_of_week: Field) -> str | None:
    """Describe the day-of-week clause, e.g. ``on Monday through Friday``."""
    if day_of_week.is_wildcard:
        return None

    names = [DAY_NAMES[value] for value in day_of_week.values]
    if day_of_week.is_simple_range:
        return f"on {names[0]} through {names[-1]}"
    return f"on {_join_text(names)}"


# --------------------------------------------------------------------------- #
# Small formatting utilities
# --------------------------------------------------------------------------- #

def _join_month_names(month: Field) -> str:
    """Join the selected month names into readable text."""
    if month.is_simple_range:
        names = [MONTH_NAMES[value - 1] for value in month.values]
        return f"{names[0]} through {names[-1]}"
    return _join_text(MONTH_NAMES[value - 1] for value in month.values)


def _join_numbers(values: tuple[int, ...]) -> str:
    """Join raw numbers into readable text."""
    return _join_text(str(value) for value in values)


def _join_text(items) -> str:
    """Join items with commas and an Oxford 'and', e.g. ``A, B, and C``."""
    items = list(items)
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return f"{', '.join(items[:-1])}, and {items[-1]}"


def _ordinal(number: int) -> str:
    """Return the ordinal form of a number, e.g. 1 -> '1st', 22 -> '22nd'."""
    if 10 <= number % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(number % 10, "th")
    return f"{number}{suffix}"


# --------------------------------------------------------------------------- #
# Demo
# --------------------------------------------------------------------------- #

if __name__ == "__main__":
    examples = [
        "* * * * *",
        "0 12 * * 1-5",
        "*/15 * * * *",
        "0 0 1 * *",
        "30 8 * * 1,3,5",
        "0 */2 * * *",
    ]
    for expr in examples:
        print(f"{expr:18} -> {parse(expr).describe()}")
```

## How it's decomposed

**Parsing** reads top-down as a funnel, each layer doing exactly one job:

- `parse` → `_split_into_fields` (arity check) → `_parse_field` (run once per field, never duplicated).
- `_parse_field` → `_parse_component` (handles one comma item) → `_split_step` (peels off `/step`) → `_parse_base_range` (resolves `*` / `a-b` / `a`) → `_parse_int` (the single point where bounds-checking and error-raising happen).

The whole `*` / range / list / step matrix collapses into one insight: every component is a `(low, high, step)` triple expanded with `range(low, high + 1, step)`. A wildcard is just the field's full range; a single value is a range where `low == high`. That's why there's no per-field special-casing.

**Description** mirrors the structure: `describe()` assembles clauses, and each `_describe_*` helper owns one clause and returns `None` when it has nothing to say (so wildcards simply drop out). Formatting trivia (Oxford commas, ordinals, month/day names) lives in small leaf utilities so the clause logic stays about *meaning*, not *string-fiddling*.

**Design choices worth noting:**
- `Field` keeps the expanded `values` (for actual scheduling logic) *and* the `raw`/`step` (so descriptions can say "every 15 minutes" instead of listing 4 numbers).
- All errors funnel through `CronParseError` (a `ValueError` subclass) with field-named messages.
- `from __future__ import annotations` keeps the `X | None` hints working on older 3.x too, though your stack is 3.13.

One honest caveat: `describe()` is tuned to read naturally for the common shapes (wildcards, single times, simple ranges, lists, steps). Exotic combinations (e.g. a stepped list in the minute field combined with a multi-value hour) fall back to the literal `"At minute … past hour …"` form — correct and unambiguous, just less polished. Extending it is purely additive: add a branch to the relevant `_describe_*` helper without touching the parser.

