"""Cron expression parser.

Parses standard 5-field cron expressions into a structured representation
and provides human-readable English descriptions.

Design emphasizes readability through small, well-named helper functions
and clear decomposition. A single shared parse_field handles all five
cron fields without duplication.
"""

from __future__ import annotations

from dataclasses import dataclass
from typing import Final, List, Set, Union


# =============================================================================
# Constants
# =============================================================================

MINUTE_RANGE: Final[tuple[int, int]] = (0, 59)
HOUR_RANGE: Final[tuple[int, int]] = (0, 23)
DAY_OF_MONTH_RANGE: Final[tuple[int, int]] = (1, 31)
MONTH_RANGE: Final[tuple[int, int]] = (1, 12)
DAY_OF_WEEK_RANGE: Final[tuple[int, int]] = (0, 6)

FIELD_SPECS: Final[List[tuple[str, tuple[int, int]]]] = [
    ("minute", MINUTE_RANGE),
    ("hour", HOUR_RANGE),
    ("day_of_month", DAY_OF_MONTH_RANGE),
    ("month", MONTH_RANGE),
    ("day_of_week", DAY_OF_WEEK_RANGE),
]

DAY_NAMES: Final[List[str]] = [
    "Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"
]

MONTH_NAMES: Final[List[str]] = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December"
]


# =============================================================================
# Field part types (discriminated values for one comma-separated segment)
# =============================================================================

@dataclass(frozen=True)
class AnyValue:
    """Wildcard: matches every value in the field's range (*)."""
    pass


@dataclass(frozen=True)
class SingleValue:
    """Exact single value (e.g. 12)."""
    value: int


@dataclass(frozen=True)
class RangeValue:
    """Inclusive range (e.g. 1-5)."""
    start: int
    end: int


@dataclass(frozen=True)
class StepValue:
    """Stepped value: base (*/ or range/ or value/) followed by /step.

    Examples: */15, 1-30/5, 0/2
    """
    base: Union[AnyValue, SingleValue, RangeValue]
    step: int


FieldPart = Union[AnyValue, SingleValue, RangeValue, StepValue]


# =============================================================================
# Structured results
# =============================================================================

@dataclass(frozen=True)
class CronField:
    """Parsed representation of one cron field (minute, hour, etc.).

    - original: the exact substring from the expression
    - parts: structured list of the comma-separated segments
    - values: concrete set of all matching integers (for schedule use)
    """
    original: str
    parts: List[FieldPart]
    min_val: int
    max_val: int
    values: frozenset[int]


@dataclass(frozen=True)
class CronExpression:
    """Structured result of parsing a full 5-field cron expression.

    The object itself is the parsed schedule. Call describe() for the
    human-readable form.
    """
    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField
    original: str

    def describe(self) -> str:
        """Return a natural English description of when this schedule runs."""
        # Fast path for the most common "always" case
        if (
            self._is_wild(self.minute)
            and self._is_wild(self.hour)
            and self._is_wild(self.day_of_month)
            and self._is_wild(self.month)
            and self._is_wild(self.day_of_week)
        ):
            return "Every minute"

        time_desc = self._describe_time_of_day()
        dom_desc = self._describe_day_of_month()
        month_desc = self._describe_month()
        dow_desc = self._describe_day_of_week()

        date_part = self._combine_date_parts(dom_desc, month_desc, dow_desc)

        # Suppress the default "every day" when the time phrase already
        # communicates a repeating interval (e.g. "Every 15 minutes").
        if date_part == "every day":
            date_part = ""

        if time_desc and date_part:
            return f"{time_desc} {date_part}"
        if time_desc:
            # Add "every day" only for absolute times that would otherwise be ambiguous
            if self._has_no_date_restriction() and time_desc.startswith("At "):
                return f"{time_desc} every day"
            return time_desc
        if date_part:
            if self._is_wild(self.minute) and self._is_wild(self.hour):
                return f"Every minute {date_part}"
            return date_part

        return "Every minute"

    # -------------------------------------------------------------------------
    # describe() helper methods (decomposed for readability)
    # -------------------------------------------------------------------------

    def _is_wild(self, field: CronField) -> bool:
        """True only when the field was written with an explicit * (full range)."""
        return len(field.parts) == 1 and isinstance(field.parts[0], AnyValue)

    def _has_no_date_restriction(self) -> bool:
        """True when day-of-month, month, and day-of-week are all unrestricted."""
        return (
            self._is_wild(self.day_of_month)
            and self._is_wild(self.month)
            and self._is_wild(self.day_of_week)
        )

    def _describe_time_of_day(self) -> str:
        """Describe the minute + hour portion, if any.

        Prefers natural phrases such as "At 12:00", "Every 15 minutes",
        "Every 2 hours, on the hour", etc.
        """
        min_f = self.minute
        hour_f = self.hour

        # 1. Minute-level step with unrestricted hours: "Every N minutes"
        if self._is_wild(hour_f) and len(min_f.parts) == 1:
            p = min_f.parts[0]
            if isinstance(p, StepValue) and isinstance(p.base, AnyValue):
                return f"Every {p.step} minutes"

        # 2. Hour-level step: "Every N hours, on the hour" or similar
        if len(hour_f.parts) == 1:
            p = hour_f.parts[0]
            if isinstance(p, StepValue):
                step = p.step
                if isinstance(p.base, AnyValue):
                    if len(min_f.values) == 1:
                        m = next(iter(min_f.values))
                        if m == 0:
                            return f"Every {step} hours, on the hour"
                        return f"Every {step} hours, at :{m:02d}"
                    return f"Every {step} hours"
                if isinstance(p.base, RangeValue):
                    # e.g. "0 1-12/4 * * *"
                    rs, re = p.base.start, p.base.end
                    if len(min_f.values) == 1 and next(iter(min_f.values)) == 0:
                        return f"Every {step} hours from {rs:02d}:00 to {re:02d}:00"
                    return f"Every {step} hours from {rs:02d} to {re:02d}"

        # 3. Concrete time(s) expressed as lists of single values in min and/or hour.
        #    This covers single times and multiple discrete times (e.g. 9:00,17:30).
        if (
            len(min_f.parts) >= 1
            and all(isinstance(p, SingleValue) for p in min_f.parts)
            and len(hour_f.parts) >= 1
            and all(isinstance(p, SingleValue) for p in hour_f.parts)
        ):
            hours = sorted(p.value for p in hour_f.parts)  # type: ignore[attr-defined]
            mins = sorted(p.value for p in min_f.parts)    # type: ignore[attr-defined]
            time_strs: List[str] = []
            for h in hours:
                for m in mins:
                    if h == 0 and m == 0:
                        time_strs.append("midnight")
                    else:
                        time_strs.append(f"{h:02d}:{m:02d}")
            if len(time_strs) == 1:
                ts = time_strs[0]
                if ts == "midnight":
                    return "At midnight"
                return f"At {ts}"
            return "At " + _join_list(time_strs)

        # 4. Fixed minute, any hour -> "Every hour, at :30"
        if len(min_f.values) == 1 and self._is_wild(hour_f):
            m = next(iter(min_f.values))
            if m == 0:
                return "Every hour, on the hour"
            return f"Every hour, at :{m:02d}"

        # 5. Any minute, fixed hour -> "Every minute past 14"
        if len(hour_f.values) == 1 and self._is_wild(min_f):
            h = next(iter(hour_f.values))
            return f"Every minute past {h:02d}"

        # 6. Fallback for ranges or mixed constructs in the time fields
        if len(hour_f.parts) == 1 and isinstance(hour_f.parts[0], RangeValue):
            r = hour_f.parts[0]
            if self._is_wild(min_f):
                return f"Every minute from {r.start:02d}:00 to {r.end:02d}:59"

        return ""

    def _describe_day_of_month(self) -> str:
        """Describe day-of-month constraints (e.g. "on the 1st", "on the 5th through the 10th")."""
        dom = self.day_of_month
        if self._is_wild(dom):
            return ""

        # Single concrete day
        if len(dom.values) == 1:
            d = next(iter(dom.values))
            return f"on the {self._ordinal(d)}"

        # One range
        if len(dom.parts) == 1 and isinstance(dom.parts[0], RangeValue):
            r = dom.parts[0]
            start_ord = self._ordinal(r.start)
            end_ord = self._ordinal(r.end)
            return f"on the {start_ord} through the {end_ord}"

        # List of singles
        if all(isinstance(p, SingleValue) for p in dom.parts):
            ordinals = [self._ordinal(p.value) for p in dom.parts]  # type: ignore[attr-defined]
            return "on the " + _join_list(ordinals)

        # Step (*/n or range/n)
        if len(dom.parts) == 1 and isinstance(dom.parts[0], StepValue):
            return self._describe_dom_step(dom.parts[0])

        return "on selected days of the month"

    def _describe_dom_step(self, step: StepValue) -> str:
        """Readable description for a stepped day-of-month part."""
        n = step.step
        if isinstance(step.base, AnyValue):
            return f"every {n} days of the month starting on the 1st"
        if isinstance(step.base, RangeValue):
            start = self._ordinal(step.base.start)
            return f"every {n} days from the {start}"
        if isinstance(step.base, SingleValue):
            start = self._ordinal(step.base.value)
            return f"every {n} days starting on the {start}"
        return f"every {n} days of the month"

    def _describe_month(self) -> str:
        """Describe month constraints."""
        m = self.month
        if self._is_wild(m):
            return ""

        if len(m.values) == 1:
            mo = next(iter(m.values))
            return f"in {MONTH_NAMES[mo - 1]}"

        if len(m.parts) == 1 and isinstance(m.parts[0], RangeValue):
            r = m.parts[0]
            return f"in {MONTH_NAMES[r.start - 1]} through {MONTH_NAMES[r.end - 1]}"

        if all(isinstance(p, SingleValue) for p in m.parts):
            names = [MONTH_NAMES[p.value - 1] for p in m.parts]  # type: ignore[attr-defined]
            return "in " + _join_list(names)

        if len(m.parts) == 1 and isinstance(m.parts[0], StepValue):
            step_desc = self._describe_generic_step(m.parts[0], "month")
            # Minor phrasing tweak for the common "every N months" case
            if step_desc.startswith("every "):
                return f"in {step_desc}"
            return step_desc

        return "in selected months"

    def _describe_day_of_week(self) -> str:
        """Describe day-of-week constraints using weekday names."""
        dow = self.day_of_week
        if self._is_wild(dow):
            return ""

        # Special-case the very common weekday range for nicer wording
        if len(dow.parts) == 1 and isinstance(dow.parts[0], RangeValue):
            r = dow.parts[0]
            if r.start == 1 and r.end == 5:
                return "on Monday through Friday"
            start_name = DAY_NAMES[r.start]
            end_name = DAY_NAMES[r.end]
            return f"on {start_name} through {end_name}"

        # Build descriptions for each comma part
        part_descs: List[str] = []
        for p in dow.parts:
            part_descs.append(self._describe_dow_part(p))

        joined = _join_list(part_descs)
        return f"on {joined}"

    def _describe_dow_part(self, part: FieldPart) -> str:
        """Describe one (non-comma) portion of a day-of-week field."""
        if isinstance(part, AnyValue):
            return "every day of the week"
        if isinstance(part, SingleValue):
            return DAY_NAMES[part.value]
        if isinstance(part, RangeValue):
            return f"{DAY_NAMES[part.start]} through {DAY_NAMES[part.end]}"
        if isinstance(part, StepValue):
            return self._describe_dow_step(part)
        return "any day"

    def _describe_dow_step(self, step: StepValue) -> str:
        """Readable description for stepped day-of-week."""
        n = step.step
        if isinstance(step.base, AnyValue):
            if n == 1:
                return "every day of the week"
            return f"every {n} days of the week"
        if isinstance(step.base, RangeValue):
            base = f"{DAY_NAMES[step.base.start]} through {DAY_NAMES[step.base.end]}"
            return f"every {n} days of the week from {base}"
        if isinstance(step.base, SingleValue):
            base = DAY_NAMES[step.base.value]
            return f"every {n} days of the week starting {base}"
        return f"every {n} days of the week"

    def _describe_generic_step(self, step: StepValue, unit: str) -> str:
        """Generic step describer used for less common fields (month, etc.)."""
        n = step.step
        if isinstance(step.base, AnyValue):
            return f"every {n} { _plural(unit, n) }"
        if isinstance(step.base, RangeValue):
            return f"every {n} { _plural(unit, n) } from {step.base.start}"
        if isinstance(step.base, SingleValue):
            return f"every {n} { _plural(unit, n) } starting at {step.base.value}"
        return f"every {n} { _plural(unit, n) }"

    def _ordinal(self, n: int) -> str:
        """Convert 1, 2, 3, ... into 1st, 2nd, 3rd, ..."""
        if 10 <= (n % 100) <= 20:
            suffix = "th"
        else:
            suffix = {1: "st", 2: "nd", 3: "rd"}.get(n % 10, "th")
        return f"{n}{suffix}"

    def _combine_date_parts(self, dom_desc: str, month_desc: str, dow_desc: str) -> str:
        """Intelligently combine dom / month / dow fragments into one phrase."""
        if dom_desc and month_desc and not dow_desc:
            # "on the 1st" + "in January"  or the special "of every month" case
            if "every month" not in month_desc:
                return f"{dom_desc} {month_desc}"
            # When month is wild we synthesize "of every month" inside dom handling
            # but here month_desc is "", see caller site in _describe_day_of_month
            pass

        if dom_desc and not month_desc and not dow_desc:
            return f"{dom_desc} of every month"

        if dom_desc and dow_desc:
            # Both dom and dow specified: cron fires on either; we surface both
            dow_clean = dow_desc[3:] if dow_desc.startswith("on ") else dow_desc
            return f"{dom_desc} and {dow_clean}"

        bits: List[str] = []
        if dom_desc:
            bits.append(dom_desc)
        if month_desc:
            bits.append(month_desc)
        if dow_desc:
            bits.append(dow_desc)
        if not bits:
            if self._has_no_date_restriction():
                return "every day"
            return ""
        return " ".join(bits)


# =============================================================================
# Pure helper functions used by describe() (defined here for top-down flow)
# =============================================================================

def _join_list(items: List[str]) -> str:
    """Join a list of strings with commas and a final 'and'."""
    if not items:
        return ""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return ", ".join(items[:-1]) + f", and {items[-1]}"


def _plural(word: str, count: int) -> str:
    """Naive pluralization sufficient for our units (hour, day, month, ...)."""
    if count == 1:
        return word
    if word.endswith("y"):
        return word[:-1] + "ies"
    if word.endswith("s"):
        return word
    return word + "s"


# =============================================================================
# Parser implementation (shared logic, no duplication across fields)
# =============================================================================

def parse_cron(expression: str) -> CronExpression:
    """Parse a standard 5-field cron expression.

    Raises ValueError with a clear message for any invalid input.
    The returned CronExpression carries both the machine-usable schedule
    (via the .values sets on each field) and the .describe() method.
    """
    if not isinstance(expression, str):
        raise ValueError("Cron expression must be a string")

    expr = expression.strip()
    if not expr:
        raise ValueError("Cron expression cannot be empty")

    fields = expr.split()
    if len(fields) != 5:
        raise ValueError(
            f"Expected exactly 5 fields (minute hour day_of_month month day_of_week), "
            f"got {len(fields)}: {expr!r}"
        )

    parsed_fields: List[CronField] = []
    for (name, (min_val, max_val)), raw in zip(FIELD_SPECS, fields):
        parsed_fields.append(parse_field(raw, min_val, max_val, name))

    return CronExpression(
        minute=parsed_fields[0],
        hour=parsed_fields[1],
        day_of_month=parsed_fields[2],
        month=parsed_fields[3],
        day_of_week=parsed_fields[4],
        original=expr,
    )


def parse_field(field_str: str, min_val: int, max_val: int, field_name: str) -> CronField:
    """Parse one cron field using a single shared implementation.

    Supports *, single values, ranges (a-b), steps (*/n, a-b/n), and
    comma-separated lists of any of the above.
    """
    if not field_str:
        raise ValueError(f"Empty {field_name} field")

    raw_segments: List[str] = []
    for seg in field_str.split(","):
        stripped = seg.strip()
        if not stripped:
            raise ValueError(f"Empty segment in {field_name} list: {field_str!r}")
        raw_segments.append(stripped)
    if not raw_segments:
        raise ValueError(f"Empty {field_name} field")

    parts: List[FieldPart] = []
    collected_values: Set[int] = set()

    for seg in raw_segments:
        part = parse_field_part(seg, min_val, max_val, field_name)
        parts.append(part)
        collected_values.update(_expand_field_part(part, min_val, max_val))

    if not collected_values:
        raise ValueError(f"{field_name} field matches no values: {field_str!r}")

    return CronField(
        original=field_str,
        parts=parts,
        min_val=min_val,
        max_val=max_val,
        values=frozenset(collected_values),
    )


def parse_field_part(part: str, min_val: int, max_val: int, field_name: str) -> FieldPart:
    """Parse a single non-comma segment of a field (*, 7, 1-5, */15, 2-30/3, ...)."""
    if "/" in part:
        if part.count("/") != 1:
            raise ValueError(f"Invalid step syntax in {field_name}: {part!r}")
        base_str, step_str = part.split("/", 1)

        if not step_str:
            raise ValueError(f"Missing step value after / in {field_name}: {part!r}")
        try:
            step = int(step_str)
        except ValueError:
            raise ValueError(f"Step must be a positive integer in {field_name}: {part!r}")
        if step <= 0:
            raise ValueError(f"Step must be a positive integer in {field_name}: {part!r}")

        base = _parse_base_for_step(base_str, min_val, max_val, field_name, part)
        return StepValue(base=base, step=step)

    if part == "*":
        return AnyValue()

    if "-" in part:
        if part.count("-") != 1:
            raise ValueError(f"Invalid range syntax in {field_name}: {part!r}")
        start_str, end_str = part.split("-", 1)
        start = _parse_int(start_str, field_name, part)
        end = _parse_int(end_str, field_name, part)

        if start < min_val or end > max_val:
            raise ValueError(
                f"Range {start}-{end} out of bounds for {field_name} "
                f"(valid range: {min_val}-{max_val})"
            )
        if start > end:
            raise ValueError(f"Start of range greater than end in {field_name}: {part!r}")

        if start == end:
            return SingleValue(start)
        return RangeValue(start, end)

    # Plain single value
    value = _parse_int(part, field_name, part)
    if value < min_val or value > max_val:
        raise ValueError(
            f"Value {value} out of bounds for {field_name} "
            f"(valid range: {min_val}-{max_val})"
        )
    return SingleValue(value)


def _parse_base_for_step(
    base_str: str, min_val: int, max_val: int, field_name: str, original_part: str
) -> Union[AnyValue, SingleValue, RangeValue]:
    """Parse the left-hand side of a step expression (the part before /)."""
    if base_str == "*":
        return AnyValue()

    if "-" in base_str:
        if base_str.count("-") != 1:
            raise ValueError(f"Invalid range before / in {field_name}: {original_part!r}")
        s_str, e_str = base_str.split("-", 1)
        start = _parse_int(s_str, field_name, original_part)
        end = _parse_int(e_str, field_name, original_part)

        if start < min_val or end > max_val or start > end:
            raise ValueError(
                f"Range {start}-{end} out of bounds for {field_name} "
                f"(valid range: {min_val}-{max_val}) in {original_part!r}"
            )
        if start == end:
            return SingleValue(start)
        return RangeValue(start, end)

    # Single value base for step (e.g. 5/15)
    val = _parse_int(base_str, field_name, original_part)
    if val < min_val or val > max_val:
        raise ValueError(
            f"Value {val} out of bounds for {field_name} "
            f"(valid range: {min_val}-{max_val}) in {original_part!r}"
        )
    return SingleValue(val)


def _expand_field_part(part: FieldPart, min_val: int, max_val: int) -> Set[int]:
    """Return the concrete integer values matched by one (non-comma) part."""
    if isinstance(part, AnyValue):
        return set(range(min_val, max_val + 1))

    if isinstance(part, SingleValue):
        return {part.value}

    if isinstance(part, RangeValue):
        return set(range(part.start, part.end + 1))

    if isinstance(part, StepValue):
        # Determine the iteration bounds from the base
        if isinstance(part.base, AnyValue):
            start = min_val
            end = max_val
        elif isinstance(part.base, RangeValue):
            start = part.base.start
            end = part.base.end
        elif isinstance(part.base, SingleValue):
            start = part.base.value
            end = max_val
        else:
            return set()

        step = part.step
        result: Set[int] = set()
        current = start
        while current <= end:
            if min_val <= current <= max_val:
                result.add(current)
            current += step
        return result

    return set()


def _parse_int(token: str, field_name: str, context: str) -> int:
    """Strict integer parse with context-rich error."""
    token = token.strip()
    if not token:
        raise ValueError(f"Empty integer value in {field_name} field: {context!r}")
    try:
        return int(token)
    except ValueError:
        raise ValueError(f"Invalid integer '{token}' in {field_name} field: {context!r}")
```

