```python
from cron_parser import parse_cron

expr = parse_cron("0 12 * * 1-5")
print(expr.describe())                 # "At 12:00 on Monday through Friday"
print(sorted(expr.day_of_week.values)) # [1, 2, 3, 4, 5]
```

